use crate::common::next_id;use crate::modules::system::AppState;use crate::modules::system::service::session_service;use axum::{extract::{Request,State},middleware::Next,response::Response};use std::time::Instant;
pub async fn record_request(State(state):State<AppState>,request:Request,next:Next)->Response{let method=request.method().as_str().to_string();let path=request.uri().path().to_string();let definition=definition(&method,&path);let started=Instant::now();let headers=request.headers().clone();let response=next.run(request).await;if let Some((module,action))=definition{if let Some(db)=state.database.as_ref(){let session=match(headers.get(&state.settings.token.name).and_then(|v|v.to_str().ok()),state.redis_pool.as_ref()){(Some(token),Some(pool))=>session_service::load_session(pool,token,state.settings.token.active_timeout_seconds).await.ok(),_=>None};let (id,name)=session.map(|s|(Some(s.user_id.value()),Some(if s.real_name.trim().is_empty(){s.username}else{s.real_name}))).unwrap_or((None,None));let status=if response.status().is_success(){"SUCCESS"}else{"FAIL"};let _=db.exec("insert into sys_operation_log(id,operator_id,operator_name,module,action,method,path,response_status,cost_ms)values(?,?,?,?,?,?,?,?,?)",vec![rbs::value!(next_id()),rbs::value!(id),rbs::value!(name),rbs::value!(module),rbs::value!(action),rbs::value!(&method),rbs::value!(&path),rbs::value!(status),rbs::value!(started.elapsed().as_millis()as i64)]).await;}}response}
fn definition(method:&str,path:&str)->Option<(&'static str,&'static str)>{let action=match(method,path){("POST",p)if p=="/api/system/login"=>return None,("POST",p)if p=="/api/system/logout"=>return None,("POST",p)if p=="/api/system/user"=>("用户管理","新增用户"),("POST",p)if p=="/api/system/job"=>("定时任务","新增任务"),("POST",p)if p.ends_with("/run")=>("定时任务","手动执行任务"),("POST",p)if p=="/api/system/files"=>("文件上传","上传文件"),("POST",p)if p.starts_with("/api/system/print-template")=>("打印模板","新增打印模板"),("PUT",p)if p.starts_with("/api/system/job")=>("定时任务","编辑任务"),("DELETE",p)if p.starts_with("/api/system/job")=>("定时任务","删除任务"),("PUT",p)if p.starts_with("/api/system/print-template")=>("打印模板","编辑打印模板"),("DELETE",p)if p.starts_with("/api/system/print-template")=>("打印模板","删除打印模板"),_=>return None};Some(action)}
